 'pouring':'mdi:weather-pouring','rainy':'mdi:weather-rainy','snowy':'mdi:weather-snowy',
 'snowy-rainy':'mdi:weather-snowy-rainy','sunny': night ? 'mdi:weather-night' : 'mdi:weather-sunny',
 'windy':'mdi:weather-windy','windy-variant':'mdi:weather-windy-variant','exceptional':'mdi:alert-circle-outline'};
var icon = w ? (map[w.state] || 'mdi:weather-partly-cloudy') : 'mdi:weather-partly-cloudy';
var c = (function(){ var t = parseFloat(states['sensor.davis_temperature'] ? states['sensor.davis_temperature'].state : 'NaN'); var w = states['weather.kmocapeg36']; var cond = w ? w.state : ''; if (isNaN(t)) return 'hsl(215 25% 62% / 0.95)'; var f = Math.min(1, Math.max(0, (t - 10) / 85)); var h = 225 - f * 213, s = 65, l = 68; if (['rainy','pouring','lightning','lightning-rainy'].indexOf(cond) >= 0) { h = 205; s = 70; } if (['snowy','snowy-rainy','hail'].indexOf(cond) >= 0) { h = 210; s = 30; l = 80; } if (['fog','cloudy'].indexOf(cond) >= 0) { s = 25; } return 'hsl(' + h + ' ' + s + '% ' + l + '% / 0.95)'; })();
