custom_fields.meta:
[[[
var w = states['weather.kmocapeg36'];
var cond = w ? w.state.replace(/-/g, ' ') : '';
cond = cond.replace('partlycloudy','partly cloudy');
cond = cond.charAt(0).toUpperCase() + cond.slice(1);
var f = (isNaN(parseFloat(states['sensor.davis_feels_like'] ? states['sensor.davis_feels_like'].state : 'NaN')) ? '–' : parseFloat(states['sensor.davis_feels_like'].state).toFixed(0));
return cond + '<span style="color:rgba(238,242,250,0.30)">  ·  </span>Feels ' + f + '°';
]]]

custom_fields.hilo:
[[[
var hi = (isNaN(parseFloat(states['sensor.kmocapeg36_forecast_temperature_0d'] ? states['sensor.kmocapeg36_forecast_temperature_0d'].state : 'NaN')) ? '–' : parseFloat(states['sensor.kmocapeg36_forecast_temperature_0d'].state).toFixed(0));
var lo = (isNaN(parseFloat(states['sensor.kmocapeg36_forecast_temperature_1n'] ? states['sensor.kmocapeg36_forecast_temperature_1n'].state : 'NaN')) ? '–' : parseFloat(states['sensor.kmocapeg36_forecast_temperature_1n'].state).toFixed(0));
var out = [];
if (hi !== '–') out.push('H ' + hi + '°');
if (lo !== '–') out.push('L ' + lo + '°');
return out.join('<span style="color:rgba(238,242,250,0.30)">  ·  </span>');
