custom_fields.chips:
[[[
var pk = parseFloat(states['sensor.davis_packets_per_min'] ? states['sensor.davis_packets_per_min'].state : 'NaN');
var mi = parseFloat(states['sensor.davis_missed_packets'] ? states['sensor.davis_missed_packets'].state : 'NaN');
var fh = states['binary_sensor.davis_fhss_locked'] ? states['binary_sensor.davis_fhss_locked'].state : 'unknown';
var lp = states['sensor.davis_last_packet'] ? states['sensor.davis_last_packet'].state : null;
var age = lp ? Math.max(0, (Date.now() - new Date(lp).getTime()) / 1000) : NaN;
var chip = function(c, icon, text) {
  return '<span style="display:inline-flex;align-items:center;gap:6px;margin-right:26px;' +
    'font-size:12.5px;font-variant-numeric:tabular-nums;color:' + c + '">' +
    '<ha-icon icon="' + icon + '" style="--mdc-icon-size:15px;color:' + c + '"></ha-icon>' +
    text + '</span>';
};
var out = '<span style="font-size:11px;font-weight:500;letter-spacing:0.12em;' +
  'text-transform:uppercase;color:rgba(238,242,250,0.30);margin-right:26px">Station</span>';
out += chip((isNaN(pk) || pk < 15) ? '#ffb454' : 'rgba(238,242,250,0.52)', 'mdi:radio-tower',
  (isNaN(pk) ? '–' : pk.toFixed(1)) + ' pkts/min');
out += chip((isNaN(mi) || mi > 5) ? '#ffb454' : 'rgba(238,242,250,0.52)', 'mdi:radio-off',
  (isNaN(mi) ? '–' : mi.toFixed(1)) + '% missed');
out += chip((fh !== 'on') ? '#ffb454' : 'rgba(238,242,250,0.52)', 'mdi:radar',
  (fh === 'on') ? 'FHSS locked' : 'FHSS unlocked');
var bat = states['binary_sensor.davis_battery'] ? states['binary_sensor.davis_battery'].state : 'unknown';
out += chip((bat === 'off') ? 'rgba(238,242,250,0.52)' : '#ffb454',
  (bat === 'on') ? 'mdi:battery-alert' : 'mdi:battery',
  (bat === 'off') ? 'Battery OK' : (bat === 'on') ? 'Battery low' : 'Battery –');
out += chip((isNaN(age) || age > 300) ? '#ffb454' : 'rgba(238,242,250,0.52)', 'mdi:clock-outline',
  isNaN(age) ? 'no packets' :
  (age < 90 ? age.toFixed(0) + ' s ago' : (age / 60).toFixed(0) + ' min ago'));
return out;
]]]

